const body = $input.first().json.body || {};

const requeridos = ['nombre', 'email', 'mensaje'];
const faltantes = requeridos.filter(c => !body[c] || body[c].trim() === '');

if (faltantes.length > 0) {
  return [{ json: { valido: false, error: `Campos obligatorios faltantes: ${faltantes.join(', ')}` } }];
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  return [{ json: { valido: false, error: `Email inválido: ${body.email}` } }];
}

const modulosMap = {
  'presupuestos': 'Presupuestos IA (Jarvis)',
  'proyectos': 'Proyectos y Kanban',
  'hitos': 'Hitos de Producción',
  'finanzas': 'Módulo Financiero',
  'canal_b2b': 'Canal B2B',
  'catalogos': 'Catálogos (Base A/B/C)',
  'clientes': 'CRM Clientes',
  'proveedores': 'Proveedores',
  'configuracion': 'Configuración y Perfil',
  'soporte': 'Soporte / Centro de Ayuda',
  'otro': 'Otro'
};

const moduloNombre = modulosMap[body.modulo] || body.modulo || 'No especificado';

const modulosPrioridad = {
  'finanzas': 'Alta',
  'presupuestos': 'Alta',
  'canal_b2b': 'Media',
  'proyectos': 'Media'
};
const prioridad = modulosPrioridad[body.modulo] || 'Normal';

const ticketId = 'TIT-' + Date.now().toString(36).toUpperCase().slice(-6);
const emoji = prioridad === 'Alta' ? '🔴' : prioridad === 'Media' ? '🟡' : '⚪';

const htmlAdmin = `
<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 600px; margin: 0 auto; padding: 24px; background: #f8f9fa; border-radius: 8px;">
  <div style="background: #4648D4; color: white; padding: 16px 24px; border-radius: 8px 8px 0 0;">
    <h1 style="margin: 0; font-size: 18px;">${emoji} Nuevo Ticket de Soporte — ${ticketId}</h1>
  </div>
  <div style="background: white; padding: 24px; border: 1px solid #e5e7eb; border-top: none; border-radius: 0 0 8px 8px;">
    <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
      <tr><td style="padding: 8px 0; color: #6b7280; font-weight: 600; width: 140px;">Ticket</td><td style="padding: 8px 0; color: #111827;">${ticketId}</td></tr>
      <tr><td style="padding: 8px 0; color: #6b7280; font-weight: 600;">Prioridad</td><td style="padding: 8px 0; color: #111827;">${emoji} ${prioridad}</td></tr>
      <tr><td style="padding: 8px 0; color: #6b7280; font-weight: 600;">Nombre</td><td style="padding: 8px 0; color: #111827;">${body.nombre}</td></tr>
      <tr><td style="padding: 8px 0; color: #6b7280; font-weight: 600;">Email</td><td style="padding: 8px 0; color: #111827;"><a href="mailto:${body.email}">${body.email}</a></td></tr>
      <tr><td style="padding: 8px 0; color: #6b7280; font-weight: 600;">Módulo</td><td style="padding: 8px 0; color: #111827;">${moduloNombre}</td></tr>
      <tr><td style="padding: 8px 0; color: #6b7280; font-weight: 600;">Asunto</td><td style="padding: 8px 0; color: #111827;">${body.asunto || 'Sin asunto'}</td></tr>
    </table>
    <hr style="border: none; border-top: 1px solid #e5e7eb; margin: 16px 0;">
    <p style="margin: 0 0 8px; color: #6b7280; font-weight: 600; font-size: 13px;">Mensaje:</p>
    <div style="background: #f3f4f6; padding: 16px; border-radius: 6px; font-size: 14px; color: #374151; line-height: 1.6;">${body.mensaje.replace(/\n/g, '<br>')}</div>
    <p style="margin: 16px 0 0; font-size: 12px; color: #9ca3af;">Enviado desde The Titan — MVP v1.0</p>
  </div>
</div>`;

const htmlUsuario = `
<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 600px; margin: 0 auto; padding: 24px; background: #f8f9fa; border-radius: 8px;">
  <div style="background: #4648D4; color: white; padding: 16px 24px; border-radius: 8px 8px 0 0;">
    <h1 style="margin: 0; font-size: 18px;">✦ Ticket recibido — ${ticketId}</h1>
  </div>
  <div style="background: white; padding: 24px; border: 1px solid #e5e7eb; border-top: none; border-radius: 0 0 8px 8px;">
    <p style="margin: 0; font-size: 14px; color: #374151;">Hola <strong>${body.nombre}</strong>,</p>
    <p style="margin: 16px 0; font-size: 14px; color: #374151; line-height: 1.6;">Hemos recibido tu consulta y te responderemos lo antes posible.</p>
    <div style="background: #f3f4f6; padding: 16px; border-radius: 6px; margin: 16px 0;">
      <p style="margin: 0; font-size: 13px; color: #6b7280;">Tu ticket: <strong style="color: #4648D4;">${ticketId}</strong></p>
      <p style="margin: 8px 0 0; font-size: 13px; color: #6b7280;">Módulo: ${moduloNombre}</p>
    </div>
    <p style="margin: 16px 0 0; font-size: 14px; color: #374151; line-height: 1.6;">Si tienes información adicional que quieras añadir, simplemente responde a este email.</p>
    <p style="margin: 24px 0 0; font-size: 13px; color: #9ca3af;">Equipo de The Titan</p>
  </div>
</div>`;

return [{
  json: {
    valido: true,
    ticketId,
    nombre: body.nombre.trim(),
    email: body.email.trim().toLowerCase(),
    modulo: body.modulo || 'otro',
    moduloNombre,
    asunto: body.asunto?.trim() || 'Sin asunto',
    mensaje: body.mensaje.trim(),
    empresa_nombre: body.empresa_nombre || 'Sin especificar',
    usuario_rol: body.usuario_rol || 'usuario',
    prioridad,
    htmlAdmin,
    htmlUsuario,
    fecha: new Date().toLocaleDateString('es-ES', {
      weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
      hour: '2-digit', minute: '2-digit'
    })
  }
}];

const items = $input.all();
const datos = $('Validar y Enriquecer Datos').first().json;

const adminResult = items[0]?.json || {};
const usuarioResult = items[1]?.json || {};

const adminOk = !adminResult.message && !adminResult.error;
const usuarioOk = !usuarioResult.message && !usuarioResult.error;

const emailsOk = adminOk && usuarioOk;
const detalle = [];
if (!adminOk) detalle.push(`Admin: ${adminResult.message || adminResult.error || 'fallo desconocido'}`);
if (!usuarioOk) detalle.push(`Usuario: ${usuarioResult.message || usuarioResult.error || 'fallo desconocido'}`);

return [{
  json: {
    success: emailsOk,
    ticketId: datos.ticketId,
    mensaje: emailsOk
      ? `Ticket ${datos.ticketId} creado. Confirmación enviada a ${datos.email}`
      : `Ticket ${datos.ticketId} registrado pero hubo problemas con emails: ${detalle.join('; ')}`,
    emails_enviados: (adminOk ? 1 : 0) + (usuarioOk ? 1 : 0),
    email_admin_ok: adminOk,
    email_usuario_ok: usuarioOk
  }
}];
